#include &lt;stdio.h&gt;
#include &lt;stdatomic.h&gt;
#include &lt;pthread.h&gt;

// 1. The Lock-Free Counter
// Multiple threads can call this safely without ANY locks.
_Atomic int global_counter = 0;

void increment_counter() {
    // The CPU hardware guarantees this +1 executes completely isolated.
    atomic_fetch_add(&global_counter, 1);
}

// 2. The Professional Spinlock
atomic_flag spin_lock = ATOMIC_FLAG_INIT;

void acquire_spinlock() {
    // atomic_flag_test_and_set atomically sets the flag to true (1),
    // and returns its PREVIOUS value. If it returns true, someone else had it.
    while (atomic_flag_test_and_set(&spin_lock)) {
        // The PAUSE instruction (via compiler intrinsic) prevents the CPU pipeline 
        // from overheating and masking out the memory bus during a tight spin.
        __builtin_ia32_pause(); 
    }
}

void release_spinlock() {
    // Instantly surrender the lock, allowing the next spinner to succeed.
    atomic_flag_clear(&spin_lock);
}

#include &lt;stdatomic.h&gt;
#include &lt;stdio.h&gt;

_Atomic int balance = 1000;

void withdraw_funds(int amount) {
    // Engineer wants to ensure the balance doesn't drop below 0

    // DANGER: We read the atomic variable
    int current = atomic_load(&balance);

    if (current >= amount) {
        // DANGER: We mutate the atomic variable
        atomic_store(&balance, current - amount);
        printf("Withdrawal successful.\n");
    }
}

#include &lt;stdatomic.h&gt;
#include &lt;stdio.h&gt;
#include &lt;pthread.h&gt;

// Shared Data
char data_payload[1024];
_Atomic int data_ready = 0;

void* producer(void* arg) {
    // 1. Write the payload using standard, non-atomic memory writes
    sprintf(data_payload, "Critical Nuclear Launch Codes");

    // 2. The Release Barrier
    // Guarantees that the sprintf string is physically flushed into the L1 Cache
    // and visible to all other CPU cores BEFORE data_ready becomes 1.
    atomic_store_explicit(&data_ready, 1, memory_order_release);
    return NULL;
}

void* consumer(void* arg) {
    int ready;
    // 3. The Acquire Barrier
    // Using a tight spinlock. Acquire guarantees that once we read '1',
    // the CPU will not maliciously pre-fetch the data_payload array early.
    do {
        ready = atomic_load_explicit(&data_ready, memory_order_acquire);
    } while (!ready);

    // 4. Safe Read
    // It is now mathematically proven that data_payload is fully synchronized.
    printf("Consumer read: %s\n", data_payload);
    return NULL;
}

#include &lt;stdatomic.h&gt;
#include &lt;stdio.h&gt;

_Atomic int events_processed = 0;

void log_event() {
    // Engineer wants maximum speed, so they use Relaxed ordering.
    // Relaxed guarantees the +1 is atomic, but asserts zero barriers.
    atomic_fetch_add_explicit(&events_processed, 1, memory_order_relaxed);
}

void print_metrics() {
    // Another thread occasionally reads the metric.
    int total = atomic_load_explicit(&events_processed, memory_order_relaxed);
    printf("Total: %d\n", total);
}

#include &lt;stdatomic.h&gt;
#include &lt;stdint.h&gt;
#include &lt;stdio.h&gt;

typedef struct Node {
    int data;
    struct Node *next;
} Node;

// To solve ABA, we must compare BOTH the pointer AND an incrementing counter.
// We pack them into a 16-byte struct (128 bits).
typedef struct {
    Node *ptr;
    uint64_t epoch; // Mutation counter
} __attribute__((aligned(16))) TaggedPointer;

// A 128-bit atomic variable. The compiler will utilize the CMPXCHG16B hardware
// instruction to swap all 16 bytes in a single hardware cycle!
_Atomic TaggedPointer head;

void push(Node *new_node) {
    TaggedPointer curr_head = atomic_load(&head);
    TaggedPointer new_head;

    new_head.ptr = new_node;

    // The CAS Loop
    do {
        new_node->next = curr_head.ptr;
        // We increment the epoch! If ABA occurs, the pointer might match,
        // but the epoch counter will NEVER match. CAS safely fails.
        new_head.epoch = curr_head.epoch + 1;

    } while (!atomic_compare_exchange_weak(&head, &curr_head, new_head));
}

#include &lt;stdatomic.h&gt;
#include &lt;stdlib.h&gt;

typedef struct Node { int data; struct Node *next; } Node;
_Atomic(Node*) head;

void pop() {
    Node *old_head;
    Node *new_head;

    do {
        old_head = atomic_load(&head);
        if (old_head == NULL) return;

        // DANGER: We read old_head->next
        new_head = old_head->next;

    } while (!atomic_compare_exchange_weak(&head, &old_head, new_head));

    // Free the popped node
    free(old_head);
}
